def export_csv(self, output_path: str, status: Optional[str] = None) -> int:
    """Export tasks to a CSV file. Returns number of tasks exported."""
    tasks = self.get_tasks(status=status)
    with open(output_path, "w", newline="") as f:
        writer = csv.writer(f)
        writer.writerow(["id", "title", "status", "created_at"])
        for task in tasks:
            writer.writerow([task.id, task.title, task.status, task.created_at])
    return len(tasks)
